// src/pages/LandingPage.jsx
import React from "react";
import landingImg from "../../public/planly.png"; // adjust if your path is different

const Landing = () => {
  return (
    <div style={styles.container}>
      <div style={styles.left}>
        <img src={landingImg} alt="Landing Visual" style={styles.image} />
      </div>
      <div style={styles.right}>
        <h1 style={styles.heading}>Welcome Back!</h1>
        <input type="text" placeholder="Search..." style={styles.searchBar} />
      </div>
    </div>
  );
};

const styles = {
  container: {
    display: "flex",
    height: "100vh",
    width: "100%",
    fontFamily: "sans-serif",
  },
  left: {
    flex: 1,
    backgroundColor: "#f4f4f4",
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
  },
  right: {
    flex: 1,
    backgroundColor: "#fff",
    padding: "2rem",
    display: "flex",
    flexDirection: "column",
    justifyContent: "center",
    alignItems: "center",
  },
  image: {
    maxWidth: "90%",
    height: "auto",
  },
  heading: {
    fontSize: "2rem",
    marginBottom: "1rem",
  },
  searchBar: {
    width: "80%",
    padding: "0.75rem 1rem",
    fontSize: "1rem",
    borderRadius: "8px",
    border: "1px solid #ccc",
    outline: "none",
  },
};

export default Landing;
